Based on the reference materials and detailed specifications, here's the complete implementation for the requested functions:

```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <type_traits>
#include <utility>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Map table name to corresponding type
  static_assert([]() -> bool {
    if (table_name == "Student") return std::is_same_v<T, Student>;
    if (table_name == "Course") return std::is_same_v<T, Course>;
    if (table_name == "Score") return std::is_same_v<T, Score>;
    if (table_name == "Major") return std::is_same_v<T, Major>;
    return false;
  }(), "Type mismatch between table name and provided type");

  // Connect to database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Use sqlgen::write to insert records
  auto write_result = sqlgen::write(conn, records);
  if (!write_result) {
    throw std::runtime_error("Failed to write records");
  }
}

void modify_eas_records_by_id(const std::string& table_name,
                               const uint32_t record_id,
                               const std::string& col_name,
                               const std::string& new_value) {
  // Map table name to corresponding type and primary key
  auto [RecordType, PrimaryKeyField] = 
      [&]() -> std::pair<std::type_index, rfl::Field> {
    if (table_name == "Student") {
      return {std::type_index(typeid(Student)), 
              rfl::make_field<"SNo">(sqlgen::PrimaryKey<sqlgen::Varchar<10>>{})};
    }
    if (table_name == "Course") {
      return {std::type_index(typeid(Course)), 
              rfl::make_field<"CID">(sqlgen::PrimaryKey<uint32_t, sqlgen::auto_incr>{})};
    }
    if (table_name == "Score") {
      return {std::type_index(typeid(Score)), 
              rfl::make_field<"ScID">(sqlgen::PrimaryKey<uint32_t, sqlgen::auto_incr>{})};
    }
    if (table_name == "Major") {
      return {std::type_index(typeid(Major)), 
              rfl::make_field<"MID">(sqlgen::PrimaryKey<uint32_t>{})};
    }
    throw std::invalid_argument("Invalid table name");
  }();

  // Read existing record
  auto read_result = sqlgen::read<std::vector<std::remove_cvref_t<RecordType>>>(
      sqlgen::sqlite::connect(db_path).value()
  ) | sqlgen::where(PrimaryKeyField == record_id);

  if (!read_result) {
    throw std::runtime_error("Failed to read record");
  }

  auto records = read_result.value();
  if (records.empty()) {
    throw std::runtime_error("Record not found");
  }

  // Modify the specified column
  auto& record = records[0];
  auto field = rfl::make_field(col_name);
  if (!field) {
    throw std::invalid_argument("Invalid column name");
  }

  // Convert new_value to appropriate type based on field type
  auto setter = [&]<typename FieldType>(const FieldType& f) {
    using T = typename FieldType::Type;
    if constexpr (std::is_same_v<T, sqlgen::Varchar<30> ||
                  std::is_same_v<T, sqlgen::Varchar<50>>) {
      return f.set(new_value);
    } else if constexpr (std::is_same_v<T, int> ||
                         std::is_same_v<T, std::optional<int>>) {
      return f.set(std::stoi(new_value));
    } else if constexpr (std::is_same_v<T, double> ||
                         std::is_same_v<T, std::optional<double>>) {
      return f.set(std::stod(new_value));
    } else if constexpr (std::is_same_v<T, uint32_t> ||
                         std::is_same_v<T, std::optional<uint32_t>>) {
      return f.set(static_cast<uint32_t>(std::stoul(new_value)));
    } else {
      static_assert(rfl::always_false_v<FieldType>, "Unsupported type");
    }
  };

  setter(field.operator()<typename decltype(field)::Name>());

  // Update the record
  auto update_result = sqlgen::write(
      sqlgen::sqlite::connect(db_path).value(),
      std::vector<RecordType>{record}
  );
  if (!update_result) {
    throw std::runtime_error("Failed to update record");
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  // Map table name to corresponding type and primary key
  auto [RecordType, PrimaryKeyField] = 
      [&]() -> std::pair<std::type_index, rfl::Field> {
    if (table_name == "Student") {
      return {std::type_index(typeid(Student)), 
              rfl::make_field<"SNo">(sqlgen::PrimaryKey<sqlgen::Varchar<10>>{})};
    }
    if (table_name == "Course") {
      return {std::type_index(typeid(Course)), 
              rfl::make_field<"CID">(sqlgen::PrimaryKey<uint32_t, sqlgen::auto_incr>{})};
    }
    if (table_name == "Score") {
      return {std::type_index(typeid(Score)), 
              rfl::make_field<"ScID">(sqlgen::PrimaryKey<uint32_t, sqlgen::auto_incr>{})};
    }
    if (table_name == "Major") {
      return {std::type_index(typeid(Major)), 
              rfl::make_field<"MID">(sqlgen::PrimaryKey<uint32_t>{})};
    }
    throw std::invalid_argument("Invalid table name");
  }();

  // Convert record_id to appropriate type
  auto id_value = PrimaryKeyField.type.visit([&](const auto& t) -> uint32_t {
    using T = std::remove_cvref_t<decltype(t)>;
    if constexpr (std::is_same_v<T, sqlgen::PrimaryKey<sqlgen::Varchar<10>>) {
      return std::stoul(record_id);
    } else {
      return static_cast<uint32_t>(std::stoul(record_id));
    }
  });

  // Delete record using sqlgen::delete_from
  auto delete_result = (sqlgen::delete_from<std::vector<std::remove_cvref_t<RecordType>>> 
                      | sqlgen::where(PrimaryKeyField == id_value))(
      sqlgen::sqlite::connect(db_path).value()
  );

  if (!delete_result) {
    throw std::runtime_error("Failed to delete record");
  }
}
```

## Key Implementation Details:

1. **Type Mapping**: Uses `std::type_index` and compile-time checks to map table names to their corresponding C++ types and primary key fields.

2. **Database Connection**: Uses `sqlgen::sqlite::connect()` to establish connections to the SQLite database.

3. **Record Insertion**: Leverages `sqlgen::write()` for batch insertion of records, automatically handling the table creation and data serialization.

4. **Record Modification**: 
   - First reads the existing record using `sqlgen::read()` with a WHERE clause
   - Uses reflection to identify and modify the specified column
   - Handles type conversion from string to appropriate C++ types
   - Updates the record using `sqlgen::write()`

5. **Record Deletion**: Uses `sqlgen::delete_from()` with a WHERE clause to delete records by primary key.

6. **Error Handling**: Comprehensive error checking at each step with meaningful error messages.

7. **Type Safety**: Ensures type safety through compile-time checks and proper use of sqlgen's type system.

The implementation follows sqlgen's principles of type-safe database operations while providing the required functionality for CRUD operations on the EAS database schema.

