             | sqlgen::join<B, "b">("id"_c == "a_id"_c)  // Join condition
             | sqlgen::where("score"_c > 10 && "name"_c.like("%x%"))  // WHERE clause
             | sqlgen::order_by("name"_c)  // ORDER BY clause
             | sqlgen::limit(10);  // LIMIT clause

