  auto conn = sqlgen::sqlite::connect();

  // 2. Build the query using select_from<Book> with appropriate column selection
  // 3. Apply order_by with pages column in descending order using desc()
  // 4. Use to<std::vector<Book>> to specify the return container type
  auto query = sqlgen::select_from<Book>("book_id"_c, "title"_c, "pages"_c)
               | sqlgen::order_by("pages"_c.desc())
               | sqlgen::to<std::vector<Book>>;

  // 5. Execute the query by calling the resulting object with the connection
  // 6. Return the result vector
  return query(conn).value();
}

}  // namespace select_from_read_to_vector
